/**
 * tokens.js — Full palette as JS constants for canvas-based controls.
 *
 * Reads ALL palette CSS custom properties from :root so that every token
 * generated by palette_tools.js is available to JS drawing code.
 * Falls back to Amber dark-theme defaults when CSS is not yet applied.
 */

function get(prop, fallback) {
  if (typeof document === "undefined") return fallback;
  const val = getComputedStyle(document.documentElement).getPropertyValue(prop).trim();
  return val || fallback;
}

export const COLORS = {
  /* Aliases (convenience shortcuts into the neutral ramp) */
  bg:        get("--bg",           "#131015"),
  panelBg:   get("--panel-bg",    "#1a1620"),
  panelEdge: get("--panel-edge",  "#221e28"),
  edge1:     get("--edge-1",      "#2a2530"),
  edge2:     get("--edge-2",      "#322d38"),
  fg:        get("--fg",          "#e8e4d8"),

  /* Full neutral ramp (12 stops, n[0]..n[11]) */
  neutral1:  get("--neutral-1",   "#131015"),
  neutral2:  get("--neutral-2",   "#1a1620"),
  neutral3:  get("--neutral-3",   "#221e28"),
  neutral4:  get("--neutral-4",   "#2a2530"),
  neutral5:  get("--neutral-5",   "#322d38"),
  neutral6:  get("--neutral-6",   "#483e50"),
  neutral7:  get("--neutral-7",   "#605568"),
  neutral8:  get("--neutral-8",   "#786d80"),
  neutral9:  get("--neutral-9",   "#908598"),
  neutral10: get("--neutral-10",  "#a89db0"),
  neutral11: get("--neutral-11",  "#c0b8c8"),
  neutral12: get("--neutral-12",  "#e8e4d8"),

  /* Primary accents (up to 7, lighter → darker) */
  accent1:  get("--primary-accent-1", "#f0c030"),
  accent2:  get("--primary-accent-2", "#e8b030"),
  accent3:  get("--primary-accent-3", "#e0a028"),
  accent4:  get("--primary-accent-4", "#d89028"),
  accent5:  get("--primary-accent-5", "#d08028"),

  /* Secondary accents (up to 7, lighter → darker) */
  secondary1: get("--secondary-accent-1", "#a888c0"),
  secondary2: get("--secondary-accent-2", "#9878b8"),
  secondary3: get("--secondary-accent-3", "#8868b0"),
  secondary4: get("--secondary-accent-4", "#7858a8"),
  secondary5: get("--secondary-accent-5", "#6848a0"),

  /* Notifications */
  colorError:   get("--color-error",   "#d04040"),
  colorWarning: get("--color-warning", "#e0a020"),
  colorSuccess: get("--color-success", "#40a060"),
  colorMessage: get("--color-message", "#4080d0"),
  colorNote:    get("--color-note",    "#808080"),

  /* Category colours (up to 7) */
  category1: get("--category-1", "#f0c030"),
  category2: get("--category-2", "#e8b030"),
  category3: get("--category-3", "#e0a028"),
  category4: get("--category-4", "#d89028"),
  category5: get("--category-5", "#d08028"),
  category6: get("--category-6", "#a888c0"),
  category7: get("--category-7", "#6848a0"),
};

/** Re-read all CSS custom properties. Call after palette-changed event. */
export function refreshColors() {
  COLORS.bg        = get("--bg",           COLORS.bg);
  COLORS.panelBg   = get("--panel-bg",    COLORS.panelBg);
  COLORS.panelEdge = get("--panel-edge",  COLORS.panelEdge);
  COLORS.edge1     = get("--edge-1",      COLORS.edge1);
  COLORS.edge2     = get("--edge-2",      COLORS.edge2);
  COLORS.fg        = get("--fg",          COLORS.fg);

  for (let i = 1; i <= 12; i++) {
    COLORS[`neutral${i}`] = get(`--neutral-${i}`, COLORS[`neutral${i}`]);
  }

  COLORS.accent1   = get("--primary-accent-1", COLORS.accent1);
  COLORS.accent2   = get("--primary-accent-2", COLORS.accent2);
  COLORS.accent3   = get("--primary-accent-3", COLORS.accent3);
  COLORS.accent4   = get("--primary-accent-4", COLORS.accent4);
  COLORS.accent5   = get("--primary-accent-5", COLORS.accent5);

  COLORS.secondary1 = get("--secondary-accent-1", COLORS.secondary1);
  COLORS.secondary2 = get("--secondary-accent-2", COLORS.secondary2);
  COLORS.secondary3 = get("--secondary-accent-3", COLORS.secondary3);
  COLORS.secondary4 = get("--secondary-accent-4", COLORS.secondary4);
  COLORS.secondary5 = get("--secondary-accent-5", COLORS.secondary5);

  COLORS.colorError   = get("--color-error",   COLORS.colorError);
  COLORS.colorWarning = get("--color-warning", COLORS.colorWarning);
  COLORS.colorSuccess = get("--color-success", COLORS.colorSuccess);
  COLORS.colorMessage = get("--color-message", COLORS.colorMessage);
  COLORS.colorNote    = get("--color-note",    COLORS.colorNote);

  COLORS.category1 = get("--category-1", COLORS.category1);
  COLORS.category2 = get("--category-2", COLORS.category2);
  COLORS.category3 = get("--category-3", COLORS.category3);
  COLORS.category4 = get("--category-4", COLORS.category4);
  COLORS.category5 = get("--category-5", COLORS.category5);
  COLORS.category6 = get("--category-6", COLORS.category6);
  COLORS.category7 = get("--category-7", COLORS.category7);
}
